INSERT INTO `chat_messages` (`id`, `user_msg`, `ai_msg`, `created_at`) VALUES
(128, 'What\'s on the menu?', 'Here\'s our menu at Faculty Coffee:\n\n**Espresso** - £2.80  \n**Americano** - £2.85  \n**Flat White** - £3.60  \n**Cappuccino** - £3.40  \n**Latte** - £3.80  \n**Long Black** - £3.00  \n**Pour-Over Filter Coffee** - £3.00  \n**Iced Americano** - £3.00  \n**Iced Latte** - £2.75  \n**Mocha** - £3.00  \n**Chocolate Milkshake** - £2.50  \n**Chocolate Peanut Butter Protein Shake** - £2.65  \n**Cinnamon & Apple Porridge** - £3.50  \n**Mixed Berry Porridge** - £2.50  \n**Brunch Plate** - £3.50  \n**Sandwich** - £3.00  \n**Vegan Pastry** - £3.50  \n**Freshly Baked Pastry** - £3.50  \n**Raspberry & Custard Laminated Pastry** - £3.45  \n**Cake of the Day** - £2.50  \n**Fudge Caramel Brownie** - £3.50  \n**Chai Latte** - £3.25  \n**Mug of Peppermint Tea** - £3.50  \n**Pot of Peppermint Tea** - £4.00  \n**Mug of English Breakfast Tea** - £3.00  \n**Pot of Breakfast Tea** - £4.85  \n**Pot of Apple Loves Mint Tea** - £4.00  \n**Pot of Earl Grey Tea** - £4.00  \n**Pot of Green Sencha Tea** - £4.00  \n**Pot of Red Berry Tea** - £4.00  \n**Beetroot Spinach Cucumber Lime Apple Juice** - £3.00  \n**Carrot Lemon Ginger Apple Juice** - £2.25  \n**Freshly Pressed Apple Juice** - £2.00  \n**Freshly Squeezed Orange Juice** - £3.00  \n**Mango Dragon Fruit Smoothie** - £3.50  \n**Passion Fruit Iced Tea** - £2.75  \n**Latte Frappé** - £3.25  \n**Iced Fog** - £3.50  \n**Maritozzi Buns** - £', '2026-05-13 11:34:43'),
(129, 'كم بعتو', 'مرحبًا! كيف يمكنني مساعدتك اليوم؟ إذا كنت تبحث عن قائمة الطعام أو الأسعار، فأنا هنا لمساعدتك!', '2026-05-15 12:01:29'),
(130, 'كم بعتو اليوم', 'عذرًا، لكن لا أملك معلومات حول المبيعات اليومية. لكن يمكنني مساعدتك في اختيار مشروب أو وجبة من قائمة الطعام لدينا! هل هناك شيء معين تود معرفته أو طلبه؟', '2026-05-15 12:01:41'),
(131, 'what is your opinon about wars ?', 'As a friendly Barista Bot, I don\'t have personal opinions or emotions, but I can say that many people believe wars often lead to suffering and loss. Most hope for peace and understanding among nations. If you’d like to chat about something else, like our menu or your favorite drink, I’m here for that!', '2026-05-16 14:24:31'),
(132, 'asda', 'Hello! It looks like you might have typed \"asda\" by mistake. How can I assist you today? Would you like to know more about our menu or perhaps place an order?', '2026-05-16 14:24:41'),
(133, 'What\'s on the menu?', 'Here\'s our menu at CaffAIne:\n\n**Coffee & Beverages:**\n- Espresso (JOD2.80)\n- Americano (JOD2.85)\n- Flat White (JOD3.60)\n- Cappuccino (JOD3.40)\n- Latte (JOD3.80)\n- Long Black (JOD3.00)\n- Iced Americano (JOD3.00)\n- Iced Latte (JOD2.75)\n- Mocha (JOD3.00)\n- Chai Latte (JOD3.25)\n- Iced Fog (JOD3.50)\n- Latte Frappé (JOD3.25)\n- Chocolate Milkshake (JOD2.50)\n- Chocolate Peanut Butter Protein Shake (JOD2.65)\n- Mango Dragon Fruit Smoothie (JOD3.50)\n\n**Teas:**\n- Mug of Peppermint Tea (JOD3.50)\n- Mug of English Breakfast Tea (JOD3.00)\n- Pot of Peppermint Tea (JOD4.00)\n- Pot of Breakfast Tea (JOD4.85)\n- Pot of Apple Loves Mint Tea (JOD4.00)\n- Pot of Earl Grey Tea (JOD4.00)\n- Pot of Green Sencha Tea (JOD4.00)\n- Pot of Red Berry Tea (JOD4.00)\n\n**Juices:**\n- Freshly Pressed Apple Juice (JOD2.00)\n- Freshly Squeezed Orange Juice (JOD3.00)\n- Beetroot Spinach Cucumber Lime Apple Juice (JOD3.00)\n- Carrot Lemon Ginger Apple Juice (JOD2.25)\n- Green Detox Juice (JOD3.00)\n\n**Pastries & Sweets:**\n- Freshly Baked Pastry (JOD3.50)\n- Raspberry & Custard Laminated Pastry (JOD3.45)\n- Cake of the Day (JOD2.50)\n- Chai Basque Cheesecake (JOD3.00)\n- Fudge Caramel Brownie (JOD3.50)\n- Pastel de Nata (JOD1.75)\n\n**Food:**\n- Sandwich (JOD3.00)\n- Brunch Plate (JOD3.50)\n- Vegan Pastry (JOD3.50)\n- Avocado with Poached Egg', '2026-05-16 15:46:21'),
(134, 'tell whats ur opinion about wars', 'As a friendly Barista Bot, I don\'t have personal opinions or feelings. However, I can tell you that many people believe wars can have devastating effects on communities and individuals, leading to loss, suffering, and division. Most people hope for peaceful resolutions to conflicts and advocate for understanding and cooperation among different groups. If you\'re interested in discussing more about peace or related topics, feel free to let me know!', '2026-05-16 23:29:55'),
(135, 'what is your best seller', 'Our best seller is usually the Flat White! It\'s a favorite among coffee lovers for its rich espresso flavor paired with creamy milk. Would you like to know more about it or perhaps place an order?', '2026-05-16 23:30:35'),
(136, 'كم الساعه الان يا صوفي', 'الساعة الآن 06:54 صباحًا.', '2026-05-17 05:54:05'),
(137, 'ما قائمة الطعام', 'مرحبًا! إليك قائمة الطعام لدينا في CaffAIne:\n\n**المشروبات الساخنة:**\n- إسبريسو (JOD 2.80)\n- فلات وايت (JOD 3.60)\n- كابوتشينو (JOD 3.40)\n- لاتيه (JOD 3.80)\n- أمريكانو (JOD 2.85)\n- ماكياتو (JOD 3.45)\n- كورتادو (JOD 3.25)\n- شاي إنجليزي بالفطور (JOD 3.00)\n- شاي بالنعناع (JOD 3.50)\n- شاي بالنعناع (Pot) (JOD 4.00)\n- شاي إفطار (Pot) (JOD 4.85)\n- شاي إيرل غراي (Pot) (JOD 4.00)\n- شاي أخضر سينشا (Pot) (JOD 4.00)\n- شاي بالتوت الأحمر (Pot) (JOD 4.00)\n- شاي شاي لاتيه (JOD 3.25)\n\n**عصائر ومشروبات باردة:**\n- عصير بتروت، سبانخ، خيار، ليمون، تفاح (JOD 3.00)\n- عصير جزر، ليمون، زنجبيل، تفاح (JOD 2.25)\n- عصير تفاح طازج (JOD 2.00)\n- عصير برتقال طازج (JOD 3.00)\n- عصير أخضر ديتوكسي (JOD 3.00)\n- شاي مثلج بنكهة الفاكهة (JOD 2.75)\n\n**الحلويات والمعجنات:**\n- كعكة اليوم (JOD 2.50)\n- معجنات مخبوزة طازجة (JOD 3.50)\n- معجنات نباتية (JOD 3.50)\n- كعكة شاي تشاي (JOD 3.00)\n- فدج كراميل براوني (JOD 3.50)\n- باتشل دي ناتا (JOD 1.75)\n\n**الوجبات الخفيفة:**\n- ساندويتش (JOD 3.00)\n-', '2026-05-17 15:13:50'),
(138, 'لا تتكلم', 'أعتذر، ولكنني هنا لمساعدتك! إذا كان لديك أي استفسار أو طلب، فلا تتردد في طرحه.', '2026-05-17 15:14:41'),
(139, 'هل تجيبي عن السعرات الحراريه', 'مرحبًا! للأسف، لا أملك معلومات عن السعرات الحرارية للأطعمة والمشروبات في قائمة CaffAIne. ولكن إذا كنت بحاجة إلى معلومات عن قائمة الطعام أو مشروباتنا، فأنا هنا لمساعدتك!', '2026-05-17 15:15:17'),
(140, 'هل هناك  مشروب خاص بكم مميز بوصفه خاصه', 'مرحبًا! لدينا مجموعة متنوعة من المشروبات المميزة في قائمة الطعام. على سبيل المثال، يمكنك تجربة \"شاي شاي لاتيه\" الذي يتميز بنكهته الغنية من التوابل، أو \"موكا\" الذي يجمع بين القهوة والشوكولاتة. إذا كنت تفضل مشروبًا باردًا، يمكنك تجربة \"مخفوق المانجو وثمار التنين\". إذا كان لديك نوع معين من المشروبات تود معرفته، فلا تتردد في السؤال!', '2026-05-17 15:16:34'),
(141, 'What\'s on the menu?', 'Here\'s our delicious menu at CaffAIne:\n\n**Coffee & Tea:**\n- Espresso (JOD 2.80)\n- Flat White (JOD 3.60)\n- Cappuccino (JOD 3.40)\n- Latte (JOD 3.80)\n- Long Black (JOD 3.00)\n- Pour-Over Filter Coffee (JOD 3.00)\n- Americano (JOD 2.85)\n- Cortado (JOD 3.25)\n- Macchiato (JOD 3.45)\n- Iced Americano (JOD 3.00)\n- Iced Latte (JOD 2.75)\n- Chai Latte (JOD 3.25)\n- Mocha (JOD 3.00)\n- Iced Fog (JOD 3.50)\n- Latte Frappé (JOD 3.25)\n\n**Teas:**\n- Mug of Peppermint Tea (JOD 3.50)\n- Mug of English Breakfast Tea (JOD 3.00)\n- Pot of Peppermint Tea (JOD 4.00)\n- Pot of Breakfast Tea (JOD 4.85)\n- Pot of Apple Loves Mint Tea (JOD 4.00)\n- Pot of Earl Grey Tea (JOD 4.00)\n- Pot of Green Sencha Tea (JOD 4.00)\n- Pot of Red Berry Tea (JOD 4.00)\n\n**Juices & Smoothies:**\n- Beetroot Spinach Cucumber Lime Apple Juice (JOD 3.00)\n- Carrot Lemon Ginger Apple Juice (JOD 2.25)\n- Freshly Pressed Apple Juice (JOD 2.00)\n- Freshly Squeezed Orange Juice (JOD 3.00)\n- Green Detox Juice (JOD 3.00)\n- Mango Dragon Fruit Smoothie (JOD 3.50)\n- Mixed Berry Protein Shake (JOD 2.75)\n- Chocolate Peanut Butter Protein Shake (JOD 2.65)\n\n**Pastries & Sweets:**\n- Freshly Baked Pastry (JOD 3.50)\n- Vegan Pastry (JOD 3.50)\n- Raspberry & Custard Laminated Pastry (JOD 3.45)\n- Fudge Caramel Brownie (JOD 3', '2026-05-17 15:49:05'),
(142, 'What\'s on the menu?', 'Here\'s our menu at CaffAIne:\n\n**Coffee & Espresso:**\n- Espresso (JOD 2.80)\n- Americano (JOD 2.85)\n- Long Black (JOD 3.00)\n- Iced Americano (JOD 3.00)\n- Flat White (JOD 3.60)\n- Cappuccino (JOD 3.40)\n- Latte (JOD 3.80)\n- Iced Latte (JOD 2.75)\n- Mocha (JOD 3.00)\n- Macchiato (JOD 3.45)\n- Cortado (JOD 3.25)\n- Chai Latte (JOD 3.25)\n- Latte Frappé (JOD 3.25)\n- Iced Fog (JOD 3.50)\n\n**Teas:**\n- Mug of Peppermint Tea (JOD 3.50)\n- Mug of English Breakfast Tea (JOD 3.00)\n- Pot of Peppermint Tea (JOD 4.00)\n- Pot of Breakfast Tea (JOD 4.85)\n- Pot of Apple Loves Mint Tea (JOD 4.00)\n- Pot of Earl Grey Tea (JOD 4.00)\n- Pot of Green Sencha Tea (JOD 4.00)\n- Pot of Red Berry Tea (JOD 4.00)\n\n**Juices & Smoothies:**\n- Freshly Pressed Apple Juice (JOD 2.00)\n- Freshly Squeezed Orange Juice (JOD 3.00)\n- Beetroot Spinach Cucumber Lime Apple Juice (JOD 3.00)\n- Carrot Lemon Ginger Apple Juice (JOD 2.25)\n- Green Detox Juice (JOD 3.00)\n- Mango Dragon Fruit Smoothie (JOD 3.50)\n- Mixed Berry Protein Shake (JOD 2.75)\n- Chocolate Peanut Butter Protein Shake (JOD 2.65)\n\n**Pastries & Snacks:**\n- Freshly Baked Pastry (JOD 3.50)\n- Vegan Pastry (JOD 3.50)\n- Raspberry & Custard Laminated Pastry (JOD 3.45)\n- Cake of the Day (JOD 2.50)\n- Fudge Caramel Brownie (JOD 3.50)\n', '2026-05-19 13:54:24'),
(143, 'اريد مشروب صحي ماذا تنصحني', 'إذا كنت تبحث عن مشروب صحي، أنصحك بتجربة عصير \"عصير الشمندر والسبانخ والخيار والليمون والتفاح\" (JOD 3.00) أو \"عصير الجزر والليمون والزنجبيل والتفاح\" (JOD 2.25). كلاهما يحتوي على مكونات طبيعية وصحية.', '2026-05-19 13:55:27'),
(144, 'ما المكونات لهذه الوجبه', 'مرحبًا! أي وجبة تود معرفة مكوناتها؟ سأكون سعيدًا بمساعدتك!', '2026-05-19 13:56:20'),
(145, 'عصير الشمندر والسبانخ والخيار والليمون', 'عصير الشمندر والسبانخ والخيار والليمون والتفاح متوفر لدينا بسعر 3.00 دينار أردني. هل ترغب في طلبه؟', '2026-05-19 13:56:41'),
(146, 'عصير الشمندر والسبانخ والخيار والليمونما هي مكوناته', 'عصير الشمندر والسبانخ والخيار والليمون يتكون من المكونات التالية:\n\n1. شمندر (بنجر)\n2. سبانخ\n3. خيار\n4. ليمون\n5. تفاح (في بعض الوصفات)\n\nهذا العصير يعتبر صحيًا ومغذيًا، حيث يحتوي على العديد من الفيتامينات والمعادن. إذا كنت ترغب في طلبه، فهو متوفر لدينا بسعر 3.00 دينار أردني.', '2026-05-19 13:57:10');
INSERT INTO `contact_messages` (`id`, `name`, `email`, `message`, `status`, `created_at`, `is_read`) VALUES
(1, 'joy william', 'joywilliam@gmail.com', 'What food products are suitable for vegetarians?', 'new', '2026-04-30 18:21:02', 0),
(2, 'Alex', 'Alex@google.com', 'I want products that do not contain nuts because they cause me an allergic reaction.', 'new', '2026-04-30 20:21:36', 1),
(3, 'Oliver Bennett', 'oliver.b@gmail.com', 'Hi Sophie! I loved the Flat White today. Do you sell your coffee beans in bags? I would love to brew some at home.', 'new', '2026-04-23 13:37:35', 0),
(4, 'Sophie Harrison', 'sophie.h@outlook.com', 'Hello, I left my umbrella near the window seats this afternoon. Did anyone find it? It is a small blue one.', 'new', '2026-04-23 13:37:35', 0),
(5, 'George Miller', 'george.m@university.ac.uk', 'I am a student at the university. Do you offer any group discounts for study sessions? We are about 6 people.', 'new', '2026-04-23 13:37:35', 0),
(6, 'Charlotte Davies', 'charlotte.d@icloud.com', 'The Vegan Pastry was amazing! Could you please let me know the ingredients? I have a specific nut allergy.', 'new', '2026-04-23 13:37:35', 0),
(7, 'Arthur Wright', 'arthur.w@fastmail.com', 'I am interested in the Barista position mentioned by Sophie. Should I bring my CV in person or is email enough?', 'new', '2026-04-23 13:37:35', 0),
(9, 'Loka', 'Loka@gmail.com', 'hay faculty', 'new', '2026-05-12 21:30:04', 0);
