INSERT INTO `menu_items` (`id`, `category_id`, `name`, `price_num`, `price_display`, `description`, `tags`, `available`, `sort_order`, `addons`, `image_url`, `created_at`) VALUES
(1, '2', 'Espresso', 2.80, 'JOD 2.80', 'A pure, bold single origin shot with a clean and bright finish. The ultimate classic coffee experience.', NULL, 1, 1, NULL, 'espresso.jpg', '2026-05-06 08:39:25'),
(2, '2', 'Flat White', 3.60, 'JOD 3.60', 'Silky microfoam with our house espresso blend', 'vegetarian', 1, 6, NULL, 'flat_white.jpg', '2026-05-06 08:39:25'),
(3, '2', 'Cappuccino', 3.40, 'JOD 3.40', 'A classic Italian coffee favorite. Made with a rich shot of espresso, topped with equal parts of velvety steamed milk and a thick, airy layer of milk foam. Perfectly balanced, creamy, and topped with a light dusting of cocoa or cinnamon.', 'vegetarian', 1, 9, NULL, 'cappuccino.jpg', '2026-05-06 08:39:25'),
(4, '2', 'Latte', 3.80, 'JOD 3.80', 'A smooth and creamy coffee classic made with a rich double shot of espresso and topped with a generous layer of silky steamed milk. Finished with a light touch of micro-foam, perfect for those who enjoy a milder coffee flavor', 'vegetarian', 1, 5, NULL, 'latte.jpg', '2026-05-06 08:39:25'),
(5, '2', 'Long Black', 3.00, 'JOD 3.00', 'A bold and sophisticated coffee made by pouring a double shot of rich espresso over hot water. This technique preserves the coffee\'s natural \"crema\" and delivers a more intense, aromatic flavor compared to a standard Americano', 'vegan', 1, 2, NULL, 'long_black.jpg', '2026-05-06 08:39:25'),
(6, '2', 'Pour-Over Filter Coffee', 3.00, 'JOD 3.00', 'A clean, light-bodied, and highly aromatic coffee brewed manually using the pour-over method. This technique highlights the delicate tasting notes and natural acidity of the coffee beans, offering a superior and refined coffee experience', 'vegan', 1, 4, NULL, 'pour-over_filter.webp', '2026-05-06 08:39:25'),
(7, '2', 'British Hot Chocolate', 4.00, 'JOD 4.00', 'A comforting and rich classic British treat. Made with premium cocoa powder blended into smooth, creamy steamed milk. This indulgent drink is served hot with a velvety texture that warms the soul, perfect for chocolate lovers seeking a traditional experience.', 'vegan', 1, 11, NULL, 'british_hot_chocolate.jpg', '2026-05-06 08:39:25'),
(8, '3', 'Freshly Baked Pastry', 3.50, 'JOD 3.50', 'Experience the golden, buttery goodness of our daily selection of artisanal pastries. From flaky croissants to rich pain au chocolat and seasonal fruit danishes, each pastry is baked fresh every morning using premium ingredients. Perfectly crisp on the outside and tender on the inside, they are the ideal companion to your morning coffee.', 'vegetarian', 1, 39, NULL, 'freshly_baked_pastry.webp', '2026-05-06 08:39:25'),
(9, '5', 'Cake of the Day', 2.50, 'JOD 2.50', 'Seasonal bakesA daily celebration of flavor and craftsmanship. Our \"Cake of the Day\" features a rotating selection of artisanal cakes, ranging from classic layered sponges and rich tortes to seasonal fruit-infused delights. Each slice is baked fresh using premium ingredients, ensuring a unique and delightful surprise with every visit. Ask our staff about today’s special creation', 'vegetarian', 1, 51, NULL, 'cake_of_the_day.jpg', '2026-05-06 08:39:25'),
(10, '3', 'Sandwich', 3.00, 'JOD 3.00', 'A vibrant and wholesome plant-based masterpiece. This multi-layered sandwich features thick slices of seeded whole-wheat bread, generously layered with creamy dill-flecked plant-based cheese, followed by layers of fresh, crisp greens: watercress, spinach, and a healthy dose of mixed microgreens. Sandwiched between these greens is a bright array of colors: ripe avocado, red onion rings, and sweet yellow and red heirloom tomato slices. A feast for the eyes and the palate', 'vegetarian', 1, 41, NULL, 'sandwich.jpg', '2026-05-06 08:39:25'),
(11, '5', 'Brunch Plate', 3.50, 'JOD 3.50', 'The ultimate morning feast, designed to satisfy every craving. Our signature Brunch Plate features two perfectly poached or scrambled eggs, crispy artisanal sourdough toast, and a side of creamy smashed avocado. Accompanied by slow-roasted cherry tomatoes, sautéed mushrooms, and a portion of fresh garden greens, this plate is a harmonious blend of textures and flavors that provides a wholesome and energizing start to your day', 'vegetarian', 1, 52, NULL, 'brunch_plate.png', '2026-05-06 08:39:25'),
(12, '3', 'Vegan Pastry', 3.50, 'JOD 3.50', 'Indulge in our selection of plant-based artisanal pastries, crafted with the same dedication to flake and flavor as our traditional range. Made using high-quality plant-based fats and organic flour, these pastries—ranging from vegan croissants to fruit-filled turnovers—offer a delicious, cruelty-free experience. Perfectly golden, crisp, and satisfyingly tender.', 'vegan', 1, 40, NULL, 'vegan_pastry.jpg', '2026-05-06 08:39:25'),
(13, '6', 'Mug of Peppermint Tea', 3.50, 'JOD 3.50', 'A naturally caffeine-free herbal infusion made from pure peppermint leaves. Served in a large mug, this refreshing and cooling tea is known for its crisp aroma and digestive benefits, making it the perfect choice for a light and soothing break.', 'vegan', 1, 14, NULL, 'mug_of_peppermint_tea.jpg', '2026-05-06 08:39:25'),
(14, '2', 'Con Panna', 3.50, 'JOD 3.50', 'A bold and elegant coffee experience. A rich double shot of espresso topped with a generous dollop of velvety, chilled whipped cream. The contrast between the hot, intense coffee and the cool, sweet cream creates a perfect balance of flavors.', 'Vegetarian,Classic,Hot', 1, 12, 'Extra Whipped Cream,Cocoa Dust,Cinnamon Sprinkle', 'con_panna.jpg', '2026-05-06 08:39:25'),
(15, '5', 'Raspberry & Custard laminated pastry.', 3.45, 'JOD 3.45', 'Crispy, buttery laminated dough filled with smooth vanilla custard and topped with fresh raspberries and a light glaze', 'Artisan,Fruit-Based,Freshly Baked,Vegetarian', 1, 55, 'Side of Fresh Raspberries,Extra Vanilla Custard Dip,Honey Drizzle', 'raspberry__custard_laminated_pastry.jpg', '2026-05-06 08:39:25'),
(16, '6', 'Mug of English Breakfast Tea', 3.00, 'JOD 3.00', 'A quintessential British classic. This full-bodied, robust black tea is served in a generous mug, offering a comforting and traditional tea experience. Perfectly balanced to be enjoyed plain or with a splash of milk.', 'Vegetarian,Classic,Hot', 1, 13, 'Mint Leaves,Extra Sugar,Lemon Slice,Honey,Extra Milk (Dairy/Oat/Almond)', 'mug_of_english_breakfast_tea.jpg', '2026-05-06 08:39:25'),
(17, '6', 'Pot of Peppermint Tea', 4.00, 'JOD 4.00', 'A soothing and naturally caffeine-free herbal infusion. This refreshing pot of tea is made from premium dried peppermint leaves, offering a cool, crisp aroma and a clean, minty finish. Perfectly served hot to aid digestion or simply to enjoy a moment of calm.', 'Vegan,Caffeine-Free,Herbal,Hot', 1, 16, 'Fresh Mint Leaves,Extra Sugar,Lemon Slice,Honey', 'pot_of_peppermint_tea.png', '2026-05-06 08:39:25'),
(18, '6', 'Pot of Breakfast Tea', 4.85, 'JOD 4.85', 'A quintessential British tradition. This robust and full-bodied black tea blend is selected for its rich, malty flavor and golden color. Served in a pot to ensure a perfectly steeped brew, it is the ideal morning pick-me-up or afternoon comfort. Best enjoyed with a splash of milk or a slice of lemon.', 'Hot,Pot,Classic,Sharing', 1, 17, 'Lemon Slice,Extra Milk (Dairy/Oat/Almond),Fresh Mint Leaves,Honey', 'pot_of_breakfast_tea.jpg', '2026-05-06 08:39:25'),
(19, '2', 'Americano', 2.85, 'JOD 2.85', 'A classic coffee favorite made by adding hot water to a double shot of espresso. This creates a smooth, well-balanced drink with a lighter body than a Long Black, perfect for those who enjoy a longer coffee experience', 'Hot,Vegan,Bold,Espresso-Based', 1, 3, 'Syrup (Caramel/Vanilla),Sugar / Honey,Oat Milk / Almond Milk,Iced (Add Ice),Extra Espresso Shot', 'americano.jpg', '2026-05-06 08:39:25'),
(20, '2', 'Cortado', 3.25, 'JOD 3.25', 'A perfectly balanced coffee consisting of equal parts rich espresso and warm, silky steamed milk. Designed to cut the acidity of the espresso while maintaining its bold flavor, offering a smooth yet strong coffee experience\n', 'Artisan,Hot,Balanced,Espresso-Based', 1, 7, 'Extra Sugar / Honey,Alternative Milk (Oat/Almond/Soy),Syrup (Caramel/Vanilla),Extra Espresso Shot', 'cortado.jpg', '2026-05-06 08:39:25'),
(21, '2', 'Macchiato', 3.45, 'JOD 3.45', 'A bold shot of espresso \'marked\' with a small dollop of velvety frothed milk', NULL, 1, 8, NULL, 'Macchiato.jpg', '2026-05-06 08:39:25'),
(22, '3', 'avocado with poached egg halloumi', 4.50, 'JOD 4.50', 'Smashed avocado on sourdough toast, topped with two perfectly poached eggs and grilled halloumi cheese', NULL, 1, 45, NULL, 'avocado_with_poached_egg__halloumi.jpg', '2026-05-06 08:39:25'),
(23, '3', 'avocado halloumi jacket potato ', 4.25, 'JOD 4.25', 'Fluffy oven-baked potato filled with creamy smashed avocado and topped with grilled halloumi cheese and a side salad', NULL, 1, 42, NULL, 'avocado__halloumi_jacket_potato_v.jpg', '2026-05-06 08:39:25'),
(24, '3', 'beans on sourdough', 5.25, 'JOD 5.25', 'Slow-cooked baked beans served on toasted artisanal sourdough bread, topped with a sprinkle of fresh herbs', NULL, 1, 50, NULL, 'beans_on_sourdough.jpg', '2026-05-06 08:39:25'),
(25, '1', 'beetroot spinach cucumber lime apple juice', 3.00, 'JOD 3.00', 'A vibrant cold-pressed blend of earthy beetroot, fresh spinach, crisp cucumber, zesty lime, and sweet green apple', NULL, 1, 25, NULL, 'beetroot_spinach_cucumber_lime__apple_juice.jpg', '2026-05-06 08:39:25'),
(26, '1', 'carrot lemon ginger apple juice', 2.25, 'JOD 2.25', 'A refreshing and spicy cold-pressed juice made with fresh carrots, zingy ginger, zesty lemon, and sweet apples', NULL, 1, 27, NULL, 'carrot_lemon_ginger__apple_juice.jpg', '2026-05-06 08:39:25'),
(27, '5', 'chai basque cheesecake', 3.00, 'JOD 3.00', 'Creamy spiced cheesecake topped with a swirl of whipped cream and dark chocolate flakes', NULL, 1, 57, NULL, 'chai_basque_cheesecake.jpg', '2026-05-06 08:39:25'),
(28, '6', 'chai latte', 3.25, 'JOD 3.25', 'A smooth blend of steamed milk and aromatic spiced black tea', NULL, 1, 15, NULL, 'chai_latte.jpg', '2026-05-06 08:39:25'),
(29, '3', 'chicken tikka jacket potato', 4.25, 'JOD 4.25', 'Fluffy baked potato topped with spicy chicken tikka and a hint of fresh cilantro', NULL, 1, 48, NULL, 'chicken_tikka_jacket_potato.jpg', '2026-05-06 08:39:25'),
(30, '1', 'chocolate milkshake', 2.50, 'JOD 2.50', 'Rich and creamy blend of premium chocolate ice cream, milk, and cocoa', NULL, 1, 36, NULL, 'chocolate_milkshake.jpg', '2026-05-06 08:39:25'),
(31, '1', 'chocolate peanut butter protein shake', 2.65, 'JOD 2.65', 'High-protein blend of smooth peanut butter, rich cocoa, and premium whey protein.', NULL, 1, 37, NULL, 'chocolate__peanut_butter_protein_shake.jpg', '2026-05-06 08:39:25'),
(32, '5', 'Cinnamon & Apple Porridge', 3.50, 'JOD 3.50', 'Creamy oats slow-cooked with fresh apple pieces and a warm dusting of cinnamon', NULL, 1, 60, NULL, 'cinnamon__apple_porridge.jpg', '2026-05-06 08:39:25'),
(33, '3', 'Eggs Florentine', 3.25, 'JOD 3.25', 'Two perfectly poached eggs with runny golden yolks served on toasted English muffins, layered with fresh sautéed spinach and topped with creamy Hollandaise sauce and cracked black pepper.', NULL, 1, 46, NULL, 'eggs_florentine.jpg', '2026-05-06 08:39:25'),
(34, '3', 'Eggs Royale', 4.50, 'JOD 4.50', 'Two poached eggs with runny yolks served on toasted English muffins, layered with premium smoked salmon and topped with rich Hollandaise sauce and cracked black pepper', NULL, 1, 47, NULL, 'eggs_royale.jpg', '2026-05-06 08:39:25'),
(35, '3', 'esquires full vegetarian', 4.00, 'JOD 4.00', 'A hearty and nutritious vegetarian breakfast featuring grilled halloumi, fresh avocado, sautéed mushrooms, slow-roasted tomatoes, baked beans, and two eggs cooked to your preference, served with toasted sourdough', NULL, 1, 49, NULL, 'esquires_full_vegetarian.jpg', '2026-05-06 08:39:25'),
(39, '1', 'freshly pressed apple juice', 2.00, 'JOD 2.00', '100% pure, natural apple juice, cold-pressed from the finest crisp apples with no added sugar or preservatives. A refreshing, vitamin-rich drink that captures the true essence of the orchard', NULL, 1, 23, NULL, 'freshly_pressed_apple_juice.jpg', '2026-05-06 08:39:25'),
(40, '1', 'freshly squeezed orange juice', 3.00, 'JOD 3.00', 'Pure, natural, and bursting with flavor. Our orange juice is squeezed to order from the finest, sun-ripened oranges. No added sugar, no preservatives—just 100% liquid sunshine in a glass. Refreshingly sweet with a hint of natural tanginess.', NULL, 1, 24, NULL, 'freshly_squeezed_orange_juice.jpg', '2026-05-06 08:39:25'),
(41, '5', 'fudge caramel brownie', 3.50, 'JOD 3.50', NULL, NULL, 1, 56, NULL, 'fudge_caramel_brownie.jpg', '2026-05-06 08:39:25'),
(44, '3', 'Halloumi & Avocado Sourdough', 4.00, 'JOD 4.00', 'A delicious and vibrant vegetarian sandwich made with toasted sourdough bread. Layered with creamy smashed avocado, fresh tomato slices, grilled halloumi cheese, and a sweet chili jam or chutney for a perfect sweet and savory balance.', NULL, 1, 43, NULL, 'halloumi__avocado_sourdough_v.jpg', '2026-05-06 08:39:25'),
(45, '1', 'icecream', 0.75, 'JOD 0.75', 'A decadent soft-serve ice cream in a classic waffle cone. Features a rim dipped in a mix of colorful sprinkles and chocolate flakes, topped with a rich chocolate flake stick and a dusting of chocolate powder', NULL, 1, 22, NULL, 'icecream.png', '2026-05-06 08:39:25'),
(54, '1', 'iced americano', 3.00, 'JOD 3.00', 'A refreshing and bold cold coffee made by combining a rich double shot of espresso with chilled filtered water over ice. Perfect for a clean, crisp caffeine boost on a warm day.', NULL, 1, 28, NULL, 'iced_americano.jpg', '2026-05-06 08:39:25'),
(55, '1', 'iced latte', 2.75, 'JOD 2.75', 'A perfectly chilled coffee classic. Features a rich double shot of espresso poured over fresh cold milk and ice cubes for a smooth, refreshing, and creamy experience.', NULL, 1, 29, NULL, 'iced_latte.jpg', '2026-05-06 08:39:25'),
(60, '1', 'Green Detox Juice (Kale, Cucumber, Spinach, Lemon & Apple)', 3.00, 'JOD 3.00', 'A vibrant and nutrient-packed cold-pressed juice. This refreshing blend combines the earthy goodness of kale and spinach with crisp cucumber, balanced by the sweetness of apple and a zesty lemon kick. The ultimate healthy refresher.', NULL, 1, 26, NULL, 'kale_cucumber_spinach_lemon__apple_juice.jpg', '2026-05-06 08:39:25'),
(61, '1', 'iced fog', 3.50, 'JOD 3.50', 'A sophisticated and refreshing tea latte made with chilled, aromatic Earl Grey tea infused with bergamot and a touch of vanilla. Shaken with cold milk and served over ice for a creamy, floral, and sweet finish.', NULL, 1, 31, NULL, 'iced-fog.png', '2026-05-06 08:39:25'),
(64, '1', 'Latte Frappé', 3.25, 'JOD 3.25', 'A luxurious, ice-blended coffee treat. This smooth Frappé combines a rich double shot of espresso with fresh milk and a hint of sweetness, all blended with ice to create a thick, frosty consistency. Topped with a light layer of foam or whipped cream for an indulgent finish.', NULL, 1, 30, NULL, 'latte_frapp.jpg', '2026-05-06 08:39:25'),
(65, '1', 'lemon lime iced', 3.00, 'JOD 3.00', 'The ultimate thirst-quencher. This crisp and invigorating iced drink features a zesty blend of freshly squeezed lemon and lime juice, balanced with a touch of sweetness and topped with sparkling or still water. Served over plenty of crushed ice, it delivers a sharp, clean, and revitalizing citrus burst that is perfect for a hot day', NULL, 1, 33, NULL, 'lemon__lime_iced_tea.jpg', '2026-05-06 08:39:25'),
(66, '1', 'mango dragon fruit smoothie', 3.50, 'JOD 3.50', 'Experience a tropical paradise in a glass. This vibrant smoothie combines the tropical sweetness of ripe mangoes with the exotic flair and stunning pink hue of dragon fruit (pitaya). Blended with a creamy base and a hint of lime, it’s a refreshing, antioxidant-packed treat that tastes as good as it looks.', NULL, 1, 35, NULL, 'mango__dragon_fruit_smoothie.jpg', '2026-05-06 08:39:25'),
(67, '5', 'maritozzi buns', 3.25, 'JOD 3.25', 'A heavenly Roman classic. These ultra-soft, brioche-style buns are delicately flavored with orange zest and honey, baked until golden, and split open to be filled with a cloud-like mountain of lightly sweetened whipped cream. Light, airy, and elegantly dusted with powdered sugar, they are a sophisticated treat that balances a rich buttery dough with a fresh, milky finish.', NULL, 1, 54, NULL, 'maritozzi_buns.jpg', '2026-05-06 08:39:25'),
(68, '5', 'mixed berry porridge', 2.50, 'JOD 2.50', 'A warm, comforting, and nutrient-dense breakfast bowl. Creamy oats slow-cooked to perfection with your choice of milk or water, swirled with a vibrant mixed berry compote. Topped with a handful of fresh blueberries, raspberries, and strawberries, and finished with a drizzle of honey or maple syrup for the perfect morning glow.', NULL, 1, 59, NULL, 'mixed_berry_porridge.jpg', '2026-05-06 08:39:25'),
(69, '1', 'mixed berry protein shake', 2.75, 'JOD 2.75', 'A powerful and delicious recovery boost. This smooth and creamy shake blends premium whey or plant-based protein with a vibrant mix of antioxidant-rich berries. Packed with high-quality nutrients and natural flavors, it’s designed to fuel your muscles and satisfy your sweet cravings in a healthy way.', NULL, 1, 38, NULL, 'mixed_berry_protein_shake.jpg', '2026-05-06 08:39:25'),
(70, '2', 'Mocha', 3.00, 'JOD 3.00', 'A delicious fusion of rich espresso and velvety steamed milk blended with premium chocolate sauce. This classic drink offers a perfect balance of coffee intensity and chocolate indulgence, topped with a smooth layer of micro-foam or whipped cream and a dusting of cocoa.', NULL, 1, 10, NULL, 'Mocha.jpg', '2026-05-06 08:39:25'),
(71, '1', 'mocha frapp', 2.75, 'JOD 2.75', 'A decadent and refreshing blended treat for coffee and chocolate lovers. This icy frappé combines rich espresso with premium chocolate sauce and fresh milk, blended with ice to a smooth, velvety consistency. Crowned with a generous swirl of whipped cream and a chocolate drizzle, it’s the ultimate cool-down indulgence', NULL, 1, 32, NULL, 'mocha_frapp.jpg', '2026-05-06 08:39:25'),
(72, '3', 'mushroom melt ', 3.50, 'JOD 3.50', 'A savory and comforting vegetarian delight. Featuring sautéed earthy mushrooms, caramelized onions, and a blend of gooey melted cheeses (Swiss or Provolone) tucked between slices of perfectly toasted artisan sourdough or ciabatta. Infused with a hint of garlic herb butter, this melt offers a rich, umami flavor in every bite.', NULL, 1, 44, NULL, 'mushroom_melt_v.jpg', '2026-05-06 08:39:25'),
(78, '1', 'passion fruit iced tea', 2.75, 'JOD 2.75', 'An exotic and refreshing escape in a glass. Our premium black tea is expertly brewed and chilled, then infused with the vibrant, tropical essence of sweet and tangy passion fruit. Served over ice for a crisp finish, this iced tea is the perfect balance of floral tea notes and bold fruit flavor.', NULL, 1, 34, NULL, 'passion_fruit_iced_tea.jpg', '2026-05-06 08:39:25'),
(79, '5', 'pastel de nata', 1.75, 'JOD 1.75', 'An authentic Portuguese classic. This world-renowned custard tart features a crisp, flaky puff pastry crust filled with a creamy, rich egg custard, lightly charred on top for a hint of caramelization. Perfectly sweet with a touch of cinnamon and lemon zest, it’s best enjoyed warm.', NULL, 1, 58, NULL, 'pastel_de_nata.jpg', '2026-05-06 08:39:25'),
(80, '6', 'Pot of Apple Loves Mint Tea', 4.00, 'JOD 4.00', 'A soothing and fragrant blend that celebrates a classic pairing. This elegant pot features premium loose-leaf tea infused with the natural sweetness of dried apple pieces and the cool, refreshing notes of fresh garden mint. Naturally aromatic and caffeine-free options available, it’s a comforting choice that cleanses the palate and warms the soul. Perfect for sharing or a long, relaxing break.', NULL, 1, 21, NULL, 'pot_of_apple_loves_mint_tea.jpg', '2026-05-06 19:51:26'),
(81, '6', 'Pot of Earl Grey Tea', 4.00, 'JOD 4.00', 'A sophisticated British classic. This elegant pot serves a premium black tea blend infused with the distinct, citrusy fragrance of oil of bergamot. Known for its bright, floral notes and bold character, our Earl Grey is brewed to perfection, offering a timeless tea experience that is both refreshing and comforting. Traditionally served black or with a splash of milk and a slice of lemon.', NULL, 1, 18, NULL, 'pot_of_earl_grey_tea.jpg', '2026-05-06 20:17:12'),
(82, '6', 'pot of green sencha tea', 4.00, 'JOD 4.00', 'A journey to the heart of Japan in every cup. This elegant pot features premium Sencha green tea, prized for its delicate balance of grassy, sweet, and umami notes. Steeped at the perfect temperature to preserve its vibrant green hue and antioxidant properties, this tea offers a clean, refreshing, and slightly nutty finish. A true masterpiece for those seeking clarity and calm', NULL, 1, 19, NULL, 'pot_of_green_sencha_tea.jpg', '2026-05-06 20:25:12'),
(83, '6', 'Pot of Red Berry Tea', 4.00, 'JOD 4.00', 'A vibrant and caffeine-free infusion that bursts with the essence of summer. This beautifully hued pot features a premium blend of dried hibiscus, rosehips, and a medley of red berries including strawberries, raspberries, and elderberries. Naturally sweet with a refreshing tart finish, it is a revitalizing choice that is as delicious as it is beautiful. Perfect for those seeking a fruit-forward, antioxidant-rich tea experience.', NULL, 1, 20, NULL, 'pot_of_red_berry_tea.jpg', '2026-05-06 21:06:59'),
(84, '5', 'very berry pancakes', 3.75, 'JOD 3.75', 'A vibrant and indulgent stack of fluffy, golden buttermilk pancakes, layered with a luscious mixed berry compote. Topped with a generous handful of fresh seasonal berries—blueberries, raspberries, and strawberries—and finished with a light dusting of powdered sugar. Served with a side of pure maple syrup or creamy mascarpone, this dish is a true celebration of berry goodness in every bite.', NULL, 1, 53, NULL, 'very_berry_pancakes.jpg', '2026-05-07 09:53:30');
